class Solution:
    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Convert all numbers to strings and store prefixes in sets
        prefixes1 = set()
        for num in arr1:
            s = str(num)
            for i in range(1, len(s) + 1):
                prefixes1.add(s[:i])

        prefixes2 = set()
        for num in arr2:
            s = str(num)
            for i in range(1, len(s) + 1):
                prefixes2.add(s[:i])

        # Find the longest common prefix
        common = prefixes1 & prefixes2
        return len(max(common, default=""))
